import{_ as e,o as r,c as o,a3 as a}from"./chunks/framework.Bwsxejtx.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),s={name:"guide/introduction.md"};function d(n,t,i,l,c,h){return r(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>AI coding assistants are generalists. They write code, but they don&#39;t enforce architecture, they don&#39;t follow your team&#39;s patterns, and they don&#39;t catch what a senior engineer would.</p><p>You end up:</p><ul><li>Re-explaining the same conventions every session</li><li>Getting &quot;it works&quot; code that doesn&#39;t match your architecture</li><li>Missing security issues, performance problems, or compliance gaps</li><li>Doing manual code review on AI-generated code</li></ul><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>Specialist Agent gives your AI assistant a team of domain experts. Instead of one generalist, you get:</p><ul><li><strong>@builder</strong> that knows your framework&#39;s component patterns</li><li><strong>@reviewer</strong> that enforces SOLID, security, and architecture rules</li><li><strong>@security</strong> that catches OWASP Top 10 issues</li><li><strong>@sentry-triage</strong> that triages production errors automatically</li></ul><p>Each agent carries specific knowledge, rules, and workflows. They don&#39;t just write code — they enforce standards.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>You install agents into your project. When you need something done, you call the right agent:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Use @builder to create the products module with CRUD</span></span>
<span class="line"><span>&gt; Use @sentry-triage to check errors from the last 24h</span></span>
<span class="line"><span>&gt; Use @reviewer to review src/modules/auth/</span></span>
<span class="line"><span>&gt; /plan add real-time notifications with WebSocket</span></span></code></pre></div><h2 id="agent-categories" tabindex="-1">Agent Categories <a class="header-anchor" href="#agent-categories" aria-label="Permalink to &quot;Agent Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Agents</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Core</strong></td><td>5</td><td>Build, review, debug, migrate</td></tr><tr><td><strong>Workflow</strong></td><td>9</td><td>Plan, execute, test, pair program</td></tr><tr><td><strong>Engineering</strong></td><td>17</td><td>API, security, data, DevOps, architecture</td></tr><tr><td><strong>Business</strong></td><td>3</td><td>Marketing, product, support</td></tr><tr><td><strong>Automation</strong></td><td>1</td><td>Sentry triage, auto-fix production errors</td></tr></tbody></table><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>Skills are repeatable workflows you invoke with a slash command:</p><table tabindex="0"><thead><tr><th>Category</th><th>Skills</th></tr></thead><tbody><tr><td>Planning</td><td><code>/brainstorm</code>, <code>/plan</code>, <code>/discovery</code>, <code>/estimate</code></td></tr><tr><td>Development</td><td><code>/tdd</code>, <code>/debug</code>, <code>/autofix</code>, <code>/lint</code>, <code>/commit</code></td></tr><tr><td>Quality</td><td><code>/verify</code>, <code>/codereview</code>, <code>/audit</code>, <code>/health</code></td></tr><tr><td>Workflow</td><td><code>/checkpoint</code>, <code>/finish</code>, <code>/worktree</code>, <code>/learn</code></td></tr><tr><td>Migration</td><td><code>/migrate-framework</code>, <code>/migrate-architecture</code></td></tr><tr><td>Knowledge</td><td><code>/remember</code>, <code>/recall</code>, <code>/onboard</code>, <code>/tutorial</code>, <code>/write-skill</code></td></tr></tbody></table><h2 id="what-makes-it-different" tabindex="-1">What Makes It Different <a class="header-anchor" href="#what-makes-it-different" aria-label="Permalink to &quot;What Makes It Different&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Generic AI</th><th>Specialist Agent</th></tr></thead><tbody><tr><td>Architecture enforcement</td><td>No</td><td>Agents enforce your ARCHITECTURE.md</td></tr><tr><td>Framework-specific patterns</td><td>Generic</td><td>7 framework packs with optimized agents</td></tr><tr><td>Code review depth</td><td>Surface-level</td><td>3-in-1 review (quality + security + architecture)</td></tr><tr><td>Production ops</td><td>Manual</td><td>@sentry-triage auto-triages errors</td></tr><tr><td>Business agents</td><td>No</td><td>@marketing, @product, @support</td></tr><tr><td>Repeatable workflows</td><td>Manual</td><td>24 skills (/plan, /tdd, /autofix, ...)</td></tr><tr><td>Multi-platform</td><td>Varies</td><td>6 platforms supported</td></tr></tbody></table><h2 id="framework-packs" tabindex="-1">Framework Packs <a class="header-anchor" href="#framework-packs" aria-label="Permalink to &quot;Framework Packs&quot;">​</a></h2><p>Each framework gets optimized agents with framework-specific patterns:</p><p><strong>Vue 3</strong> | <strong>React</strong> | <strong>Next.js</strong> | <strong>SvelteKit</strong> | <strong>Angular</strong> | <strong>Astro</strong> | <strong>Nuxt</strong></p><h2 id="platform-support" tabindex="-1">Platform Support <a class="header-anchor" href="#platform-support" aria-label="Permalink to &quot;Platform Support&quot;">​</a></h2><p>Works on: <strong>Claude Code</strong>, <strong>Cursor</strong>, <strong>VS Code</strong>, <strong>Windsurf</strong>, <strong>Codex</strong>, <strong>OpenCode</strong></p><h2 id="who-it-s-for" tabindex="-1">Who It&#39;s For <a class="header-anchor" href="#who-it-s-for" aria-label="Permalink to &quot;Who It&#39;s For&quot;">​</a></h2><ul><li><strong>Solo developers</strong> who want senior-level review on every commit</li><li><strong>Teams</strong> who want to standardize how AI assists development</li><li><strong>Startups</strong> who need to move fast without accumulating tech debt</li><li><strong>Enterprise</strong> teams who need compliance, security, and architecture enforcement</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-70/guide/quick-start.html">Quick Start</a> — Install and use your first agent</li><li><a href="/pr-preview/pr-70/reference/agents.html">Agent Catalog</a> — Browse all 35 agents</li><li><a href="/pr-preview/pr-70/reference/skills.html">Skills Reference</a> — All 24 skills</li></ul>`,28)])])}const g=e(s,[["render",d]]);export{p as __pageData,g as default};
